function lengthOfLastWord(str) {
  let i = str.length - 1;
  let length = 0;

  // Skip trailing spaces
  while (i >= 0 && str[i] === " ") i--;

  // Count the length of the last word
  while (i >= 0 && str[i] !== " ") {
    length++;
    i--;
  }

  return length;
}

